import java.util.ArrayList;
import java.util.Collections;
import java.util.Comparator;
import java.util.List;

public class ScratchPad {

    private static class Interval {
        int start;
        int end;

        Interval(int start, int end) {
            this.start = start;
            this.end = end;
        }
    }

    private static class IntervalComparator implements Comparator<Interval> {
        @Override
        public int compare(Interval a, Interval b) {
            if (a.end != b.end) {
                return a.end - b.end;
            } else {
                return a.start - b.start;
            }
        }
    }

    public static List<Integer> findMinimumNumbers(List<Interval> intervals, int k) {
        Collections.sort(intervals, new IntervalComparator());
        List<Integer> result = new ArrayList<Integer>();

        int preStart = intervals.get(0).end - k + 1;
        int preEnd = intervals.get(0).end;

        for (int i = 1; i < intervals.size(); i++) {
            Interval current = intervals.get(i);

            if (current.start <= preStart) continue;

            if (current.start <= preEnd) {
                for (int j = preStart; j < current.start; j++) {
                    result.add(j);
                }
                preStart = current.start;
                preEnd = preStart + k - 1;
                continue;
            }

            for (int j = preStart; j <= preEnd; j++) {
                result.add(j);
            }
            preStart = current.end - k + 1;
            preEnd = current.end;
        }

        for (int i = preStart; i <= preEnd; i++) {
            result.add(i);
        }

        return result;
    }

    public static void main(String[] args) {
        List<Interval> intervals1 = new ArrayList<Interval>();
        intervals1.add(new Interval(1, 4));
        intervals1.add(new Interval(5, 6));
        System.out.println(findMinimumNumbers(intervals1, 2));

        List<Interval> intervals2 = new ArrayList<Interval>();
        intervals2.add(new Interval(1, 4));
        intervals2.add(new Interval(3, 6));
        intervals2.add(new Interval(2, 4));
        System.out.println(findMinimumNumbers(intervals2, 2));

        // Add other test cases here following the same pattern
    }
}


